	public static IUniTaskAsyncEnumerable<int> Range(int start, int count)
	{
		if (count < 0)
		{
			throw Error.ArgumentOutOfRange("count");
		}
		if ((long)start + (long)count - 1 > int.MaxValue)
		{
			throw Error.ArgumentOutOfRange("count");
		}
		if (count == 0)
		{
			Empty<int>();
		}
		return new Range(start, count);
	}

